import{_ as n,o as a,c as p,ae as t}from"./chunks/framework.Czhw_PXq.js";const g=JSON.parse('{"title":"Agent 生命周期","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/19_Agent管理专题/07-lifecycle.md","filePath":"chapters/19_Agent管理专题/07-lifecycle.md"}'),e={name:"chapters/19_Agent管理专题/07-lifecycle.md"};function l(o,s,d,i,r,c){return a(),p("div",null,[...s[0]||(s[0]=[t(`<h1 id="agent-生命周期" tabindex="-1">Agent 生命周期 <a class="header-anchor" href="#agent-生命周期" aria-label="Permalink to &quot;Agent 生命周期&quot;">​</a></h1><blockquote><p>日期：2026-03-25 来源：内容运营助手群</p></blockquote><hr><p>user: openclaw的agent从用户需求响应的全部流程以及agent状态的监控,agent自身的学习,进化,更新loop流程是什么</p><p>assistant: 根据 OpenClaw 官方文档，我来系统性地分析 Agent 的完整生命周期。</p><hr><h2 id="openclaw-agent-完整生命周期" tabindex="-1">OpenClaw Agent 完整生命周期 <a class="header-anchor" href="#openclaw-agent-完整生命周期" aria-label="Permalink to &quot;OpenClaw Agent 完整生命周期&quot;">​</a></h2><h3 id="📊-一、用户需求响应流程" tabindex="-1">📊 一、用户需求响应流程 <a class="header-anchor" href="#📊-一、用户需求响应流程" aria-label="Permalink to &quot;📊 一、用户需求响应流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        1. 消息入口                                    │</span></span>
<span class="line"><span>│         用户在 Telegram 群发送消息 → Gateway 接收                     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                                │</span></span>
<span class="line"><span>                                ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        2. Binding 匹配                               │</span></span>
<span class="line"><span>│         Gateway 根据 binding 规则 → 分发到对应 Agent                  │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                                │</span></span>
<span class="line"><span>                                ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        3. Session 管理                               │</span></span>
<span class="line"><span>│         加载/创建 Session → 加载 Workspace 上下文                     │</span></span>
<span class="line"><span>│         - SOUL.md (角色定义)                                        │</span></span>
<span class="line"><span>│         - AGENTS.md (指令)                                          │</span></span>
<span class="line"><span>│         - MEMORY.md (长期记忆)                                      │</span></span>
<span class="line"><span>│         - memory/YYYY-MM-DD.md (每日记录)                          │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                                │</span></span>
<span class="line"><span>                                ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        4. Prompt 组装                                │</span></span>
<span class="line"><span>│         构建系统提示：基础提示 + Skills + 上下文 + 引导               │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                                │</span></span>
<span class="line"><span>                                ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        5. 模型推理                                    │</span></span>
<span class="line"><span>│         调用 LLM (MiniMax) → 流式输出                                │</span></span>
<span class="line"><span>│         - thinking (推理)                                          │</span></span>
<span class="line"><span>│         - assistant (回复)                                          │</span></span>
<span class="line"><span>│         - tool (工具调用)                                          │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                                │</span></span>
<span class="line"><span>                                ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        6. 工具执行                                    │</span></span>
<span class="line"><span>│         Agent 调用工具 → 执行 → 返回结果                             │</span></span>
<span class="line"><span>│         - memory_search / memory_get (记忆)                          │</span></span>
<span class="line"><span>│         - sessions_spawn (调用子 Agent)                             │</span></span>
<span class="line"><span>│         - 其他工具                                                 │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                                │</span></span>
<span class="line"><span>                                ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        7. 响应返回                                   │</span></span>
<span class="line"><span>│         流式返回给用户 → Session 持久化                            │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><hr><h3 id="📊-二、agent-状态监控" tabindex="-1">📊 二、Agent 状态监控 <a class="header-anchor" href="#📊-二、agent-状态监控" aria-label="Permalink to &quot;📊 二、Agent 状态监控&quot;">​</a></h3><table tabindex="0"><thead><tr><th>监控维度</th><th>说明</th><th>工具/方法</th></tr></thead><tbody><tr><td><strong>Session 状态</strong></td><td>活跃会话数、Token 使用量</td><td><code>openclaw status</code></td></tr><tr><td><strong>运行时状态</strong></td><td>PID、内存、运行时间</td><td>Gateway Dashboard</td></tr><tr><td><strong>心跳监控</strong></td><td>定时健康检查</td><td><code>HEARTBEAT.md</code></td></tr><tr><td><strong>错误追踪</strong></td><td>错误日志、异常捕获</td><td><code>openclaw logs</code></td></tr><tr><td><strong>Cron 任务</strong></td><td>定时任务执行状态</td><td><code>openclaw cron list</code></td></tr></tbody></table><p><strong>Session 存储位置</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.openclaw/agents/&lt;agent_id&gt;/sessions/</span></span>
<span class="line"><span>├── &lt;session_id&gt;.jsonl  ← 会话历史</span></span>
<span class="line"><span>└── ...</span></span></code></pre></div><hr><h3 id="📊-三、agent-学习-进化-更新-loop" tabindex="-1">📊 三、Agent 学习/进化/更新 Loop <a class="header-anchor" href="#📊-三、agent-学习-进化-更新-loop" aria-label="Permalink to &quot;📊 三、Agent 学习/进化/更新 Loop&quot;">​</a></h3><h4 id="_1-学习机制-memory" tabindex="-1">1. 学习机制（Memory） <a class="header-anchor" href="#_1-学习机制-memory" aria-label="Permalink to &quot;1. 学习机制（Memory）&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              短期记忆 (Session)              │</span></span>
<span class="line"><span>│         当前对话上下文 (自动管理)             │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>                    ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              每日记录 (Daily)                │</span></span>
<span class="line"><span>│    memory/YYYY-MM-DD.md (每日新增)          │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>                    ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              长期记忆 (Long-term)           │</span></span>
<span class="line"><span>│           MEMORY.md (人工/自动提炼)         │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>自动记忆 flush</strong>：</p><ul><li>当 Session 接近上下文压缩时</li><li>OpenClaw 会触发一个<strong>静默的 Agent 轮次</strong></li><li>提醒模型在压缩前<strong>写入持久记忆</strong></li></ul><h4 id="_2-进化机制-evolution" tabindex="-1">2. 进化机制（Evolution） <a class="header-anchor" href="#_2-进化机制-evolution" aria-label="Permalink to &quot;2. 进化机制（Evolution）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>进化方式</th><th>说明</th></tr></thead><tbody><tr><td><strong>手动更新</strong></td><td>直接修改 SOUL.md / AGENTS.md</td></tr><tr><td><strong>自动学习</strong></td><td>通过 memory_flush 自动写入偏好</td></tr><tr><td><strong>用户反馈</strong></td><td>用户说 &quot;记住这个&quot; → 写入 MEMORY.md</td></tr><tr><td><strong>上下文压缩</strong></td><td>summarization 保留关键信息</td></tr></tbody></table><p><strong>触发记忆写入</strong>：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">用户: &quot;记住我喜欢麻辣口味&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">→ Agent 调用 memory_get/write</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">→ 写入 MEMORY.md 或 memory/YYYY-MM-DD.md</span></span></code></pre></div><h4 id="_3-更新-loop-流程" tabindex="-1">3. 更新 Loop 流程 <a class="header-anchor" href="#_3-更新-loop-流程" aria-label="Permalink to &quot;3. 更新 Loop 流程&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              触发条件                        │</span></span>
<span class="line"><span>│  1. 用户明确要求 (&quot;记住...&quot;)                 │</span></span>
<span class="line"><span>│  2. 上下文即将压缩 (pre-compaction)         │</span></span>
<span class="line"><span>│  3. Session 结束 (/reset)                  │</span></span>
<span class="line"><span>│  4. 手动编辑配置文件                        │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>                    ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              执行更新                        │</span></span>
<span class="line"><span>│  - 写入 memory/YYYY-MM-DD.md               │</span></span>
<span class="line"><span>│  - 更新 MEMORY.md (重要/持久信息)           │</span></span>
<span class="line"><span>│  - 更新 SOUL.md (角色变化)                  │</span></span>
<span class="line"><span>│  - 更新 AGENTS.md (指令变化)                │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>                    ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              验证生效                        │</span></span>
<span class="line"><span>│  - 下次 Session 加载新上下文               │</span></span>
<span class="line"><span>│  - 通过 memory_search 验证记忆可检索        │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre></div><hr><h3 id="📊-四、关键配置文件" tabindex="-1">📊 四、关键配置文件 <a class="header-anchor" href="#📊-四、关键配置文件" aria-label="Permalink to &quot;📊 四、关键配置文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件</th><th>位置</th><th>作用</th></tr></thead><tbody><tr><td><strong>SOUL.md</strong></td><td>workspace/</td><td>Agent 角色定义</td></tr><tr><td><strong>AGENTS.md</strong></td><td>workspace/</td><td>指令和行为规范</td></tr><tr><td><strong>MEMORY.md</strong></td><td>workspace/</td><td>长期记忆</td></tr><tr><td><strong>memory/YYYY-MM-DD.md</strong></td><td>workspace/</td><td>每日记录</td></tr><tr><td><strong>HEARTBEAT.md</strong></td><td>workspace/</td><td>心跳检查任务</td></tr></tbody></table><hr><h3 id="📊-五、hook-拦截点" tabindex="-1">📊 五、Hook 拦截点 <a class="header-anchor" href="#📊-五、hook-拦截点" aria-label="Permalink to &quot;📊 五、Hook 拦截点&quot;">​</a></h3><p>可以在以下位置拦截和扩展：</p><table tabindex="0"><thead><tr><th>Hook 事件</th><th>时机</th></tr></thead><tbody><tr><td><code>agent:bootstrap</code></td><td>Bootstrap 文件加载前</td></tr><tr><td><code>before_model_resolve</code></td><td>模型解析前</td></tr><tr><td><code>before_prompt_build</code></td><td>Prompt 构建前</td></tr><tr><td><code>before_tool_call</code></td><td>工具调用前</td></tr><tr><td><code>after_tool_call</code></td><td>工具调用后</td></tr><tr><td><code>message:received</code></td><td>收到消息时</td></tr><tr><td><code>message:sent</code></td><td>消息发送后</td></tr><tr><td><code>session:compact:before</code></td><td>上下文压缩前</td></tr><tr><td><code>session:compact:after</code></td><td>上下文压缩后</td></tr></tbody></table><hr><p>这样就构成了一个完整的 <strong>感知 → 记忆 → 思考 → 行动 → 学习 → 进化</strong> 的 Agent 循环！</p>`,35)])])}const m=n(e,[["render",l]]);export{g as __pageData,m as default};
